import React, { useState, useEffect } from 'react';
import './Settings.css';
import ChatBox from './ChatBox';  // Import ChatBox

const Settings = () => {
  const [isLocked, setIsLocked] = useState(true);
  const [detailsList, setDetailsList] = useState([]);
  const [selectedCredential, setSelectedCredential] = useState(null);
  const [domain, setDomain] = useState('');
  const [project, setProject] = useState('');
  const [issueType, setIssueType] = useState('');

  useEffect(() => {
    fetchDetails();
  }, []);

  const fetchDetails = async () => {
    try {
      const response = await fetch('https://localhost:7216/api/Details');
      if (response.ok) {
        const data = await response.json();
        setDetailsList(data);
      } else {
        console.error('Failed to fetch details:', response.statusText);
      }
    } catch (error) {
      console.error('Error fetching details:', error);
    }
  };

  const handleLockToggle = () => {
    setIsLocked(!isLocked);
  };

  const handleSelectCredential = (credential) => {
    setSelectedCredential(credential);
    setDomain(credential.Domain);  // Set domain from selected credential
    setProject(credential.Project);  // Set project from selected credential
    setIssueType(credential.IssueType);  // Set issue type from selected credential
    setIsLocked(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!selectedCredential) {
      alert('Please select a credential to update or enter a new one.');
      return;
    }

    const newCredential = { Domain: domain, Project: project, IssueType: issueType };

    try {
      const response = await fetch('https://localhost:7216/api/Details/Manage', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newCredential),
      });

      if (response.ok) {
        const { data } = await response.json();
        setDetailsList((prevDetails) => [...prevDetails, data]);
        alert('Credential saved successfully');
      } else {
        const errorMessage = await response.text();
        console.error('Failed to save credential:', errorMessage);
        alert('Failed to save credential');
      }
    } catch (error) {
      console.error('Error saving credential:', error);
      alert('Error saving credential');
    }
  };

  return (
    <div className="settings-container">
      <h2>Jira Settings</h2>

      <h3>Add or Update Credential</h3>
      <form onSubmit={handleSubmit}>
        <div>
          <label>Domain:</label>
          <input
            type="text"
            value={domain}
            onChange={(e) => setDomain(e.target.value)}
            disabled={isLocked}
          />
        </div>
        <div>
          <label>Project:</label>
          <input
            type="text"
            value={project}
            onChange={(e) => setProject(e.target.value)}
            disabled={isLocked}
          />
        </div>
        <div>
          <label>Issue Type:</label>
          <input
            type="text"
            value={issueType}
            onChange={(e) => setIssueType(e.target.value)}
            disabled={isLocked}
          />
        </div>
        <div>
          <label>
            <input type="checkbox" checked={!isLocked} onChange={handleLockToggle} />
            Unlock to Edit
          </label>
        </div>
        <div>
          <button type="submit" disabled={isLocked}>Save</button>
        </div>
      </form>

      <div className="details-list">
        <h3>Saved Credentials</h3>
        <table className="details-table">
          <thead>
            <tr>
              <th>Domain</th>
              <th>Project</th>
              <th>Issue Type</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {detailsList.map((detail) => (
              <tr key={`${detail.Domain}-${detail.Project}-${detail.IssueType}`} onClick={() => handleSelectCredential(detail)}>
                <td>{detail.Domain}</td>
                <td>{detail.Project}</td>
                <td>{detail.IssueType}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Pass the selected domain, project, and issue type as props to ChatBox */}
      <ChatBox domain={domain} project={project} issueType={issueType} />
    </div>
  );
};

export default Settings;
